// nodes/BaseNode.js
// Core abstraction layer â€” renders any node from a declarative config.
// Supports: field rendering, handle labels, glassmorphism, accent glow.

import { Handle, Position } from 'reactflow';
import { motion } from 'framer-motion';
import { useStore } from '../store';
import { useCallback, useRef, useEffect, useState } from 'react';

// â”€â”€â”€ Field Renderers â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
// Each field type maps to a renderer that emits the right control.

const AutoTextarea = ({ value, onChange, placeholder, style }) => {
  const ref = useRef(null);
  useEffect(() => {
    if (ref.current) {
      ref.current.style.height = 'auto';
      ref.current.style.height = ref.current.scrollHeight + 'px';
    }
  }, [value]);
  return (
    <textarea
      ref={ref}
      className="node-field-input node-field-textarea"
      value={value}
      onChange={onChange}
      placeholder={placeholder}
      style={{ ...style, overflow: 'hidden', resize: 'none' }}
      rows={1}
    />
  );
};

const fieldRenderers = {
  text: ({ field, value, onChange }) => (
    <input
      className="node-field-input"
      type="text"
      value={value ?? field.default ?? ''}
      onChange={(e) => onChange(e.target.value)}
      placeholder={field.placeholder || ''}
    />
  ),

  textarea: ({ field, value, onChange }) => (
    <AutoTextarea
      value={value ?? field.default ?? ''}
      onChange={(e) => onChange(e.target.value)}
      placeholder={field.placeholder || ''}
      style={{ fontFamily: field.mono ? "'JetBrains Mono', 'Fira Code', monospace" : 'inherit' }}
    />
  ),

  select: ({ field, value, onChange }) => (
    <div className="node-field-select-wrap">
      <select
        className="node-field-select"
        value={value ?? field.default ?? (field.options?.[0]?.value ?? field.options?.[0]) ?? ''}
        onChange={(e) => onChange(e.target.value)}
      >
        {(field.options || []).map((opt) => {
          const val = typeof opt === 'string' ? opt : opt.value;
          const label = typeof opt === 'string' ? opt : opt.label;
          return <option key={val} value={val}>{label}</option>;
        })}
      </select>
      <svg className="node-field-select-arrow" width="10" height="6" viewBox="0 0 10 6" fill="none">
        <path d="M1 1L5 5L9 1" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
      </svg>
    </div>
  ),

  slider: ({ field, value, onChange }) => {
    const v = value ?? field.default ?? field.min ?? 0;
    return (
      <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
        <input
          className="node-field-slider"
          type="range"
          min={field.min ?? 0}
          max={field.max ?? 100}
          step={field.step ?? 1}
          value={v}
          onChange={(e) => onChange(e.target.value)}
        />
        <span className="node-field-slider-value">{v}</span>
      </div>
    );
  },

  badge: ({ field, value }) => (
    <span
      className="node-field-badge"
      style={{ '--badge-color': field.color || 'var(--accent-blue)' }}
    >
      {value ?? field.default ?? field.label}
    </span>
  ),

  code: ({ field, value, onChange }) => (
    <AutoTextarea
      value={value ?? field.default ?? ''}
      onChange={(e) => onChange(e.target.value)}
      placeholder={field.placeholder || '// code...'}
      style={{ fontFamily: "'JetBrains Mono', 'Fira Code', monospace", fontSize: '11px' }}
    />
  ),

  display: ({ field, value }) => (
    <div className="node-field-display">
      {value ?? field.default ?? 'â€”'}
    </div>
  ),

  chips: ({ field, value }) => {
    const items = value ?? field.default ?? [];
    return (
      <div className="node-field-chips">
        {(Array.isArray(items) ? items : [items]).map((item, i) => (
          <span key={i} className="node-field-chip" style={{ '--chip-color': field.color || 'var(--accent-blue)' }}>
            {item}
          </span>
        ))}
      </div>
    );
  },
};

// â”€â”€â”€ BaseNode Component â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

export const BaseNode = ({
  id,
  title,
  icon: Icon,
  accentColor = 'var(--accent-blue)',
  inputs = [],
  outputs = [],
  fields = [],
  data = {},
  children,
  style = {},
  selected = false,
  minWidth = 220,
}) => {
  const updateNodeField = useStore((s) => s.updateNodeField);
  const [hovered, setHovered] = useState(false);

  const handleFieldChange = useCallback(
    (fieldKey, value) => {
      updateNodeField(id, fieldKey, value);
    },
    [id, updateNodeField]
  );

  // Calculate handle positions
  const getHandleTop = (index, total) => {
    if (total === 1) return '50%';
    const start = 25;
    const end = 75;
    const pct = start + (index / (total - 1)) * (end - start);
    return `${pct}%`;
  };

  return (
    <motion.div
      initial={{ opacity: 0, scale: 0.92, y: 8 }}
      animate={{ opacity: 1, scale: 1, y: 0 }}
      transition={{ duration: 0.3, ease: [0.16, 1, 0.3, 1] }}
      className={`base-node ${selected ? 'selected' : ''} ${hovered ? 'hovered' : ''}`}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      style={{
        '--accent': accentColor,
        minWidth,
        ...style,
      }}
    >
      {/* Accent strip at top */}
      <div className="base-node-accent" style={{ background: accentColor }} />

      {/* Header */}
      <div className="base-node-header">
        <div className="base-node-icon" style={{ '--icon-color': accentColor }}>
          {Icon && <Icon size={15} strokeWidth={2.5} />}
        </div>
        <span className="base-node-title">{title}</span>
      </div>

      {/* Fields */}
      {fields.length > 0 && (
        <div className="base-node-body">
          {fields.map((field) => {
            const Renderer = fieldRenderers[field.type];
            if (!Renderer) return null;
            return (
              <div key={field.key} className="base-node-field">
                {field.label && field.type !== 'badge' && (
                  <label className="base-node-field-label">{field.label}</label>
                )}
                <Renderer
                  field={field}
                  value={data[field.key]}
                  onChange={(v) => handleFieldChange(field.key, v)}
                />
              </div>
            );
          })}
        </div>
      )}

      {/* Custom children (for special nodes like Text) */}
      {children && <div className="base-node-body">{children}</div>}

      {/* Input Handles (left side) */}
      {inputs.map((handle, i) => (
        <div key={handle.id} className="base-node-handle-group left">
          <Handle
            type="target"
            position={Position.Left}
            id={handle.id}
            className="base-node-handle"
            style={{
              top: getHandleTop(i, inputs.length),
              '--handle-color': accentColor,
            }}
          />
          {handle.label && (
            <span
              className="base-node-handle-label left"
              style={{ top: getHandleTop(i, inputs.length) }}
            >
              {handle.label}
            </span>
          )}
        </div>
      ))}

      {/* Output Handles (right side) */}
      {outputs.map((handle, i) => (
        <div key={handle.id} className="base-node-handle-group right">
          <Handle
            type="source"
            position={Position.Right}
            id={handle.id}
            className="base-node-handle"
            style={{
              top: getHandleTop(i, outputs.length),
              '--handle-color': accentColor,
            }}
          />
          {handle.label && (
            <span
              className="base-node-handle-label right"
              style={{ top: getHandleTop(i, outputs.length) }}
            >
              {handle.label}
            </span>
          )}
        </div>
      ))}
    </motion.div>
  );
};
